#include <stdlib.h>
#include <string.h>

typedef struct {
    char title[32];
    int code;
} Status;

Status* build_status() {
    Status* s = malloc(sizeof(Status));
    strcpy(s->title, "Ok");
    s->code = 200;
    return s;
}

